def calculate_war_durations():
    wars = {
        "First Anglo-Ashanti War": (1822, 1824),
        "Second Anglo-Ashanti War": (1873, 1874),
        "Third Anglo-Ashanti War": (1893, 1894),
        "Fourth Anglo-Ashanti War": (1895, 1896)
    }
    durations = {war: end_year - start_year + 1 for war, (start_year, end_year) in wars.items()}
    return durations

# Example usage:
print(calculate_war_durations())

This function returns the duration of each Anglo-Ashanti war in years.
